// Get display name for any item ID (any tier)
function getItemName(itemId) {
  if (!itemId) return itemId;
  // Try exact match first
  if (ITEM_NAMES[itemId]) return ITEM_NAMES[itemId];
  // Strip tier to get base key, then look up by base
  const base = itemId.replace(/^T\d_/, 'T4_');
  if (ITEM_NAMES[base]) return ITEM_NAMES[base];
  // Fall back to ID without tier prefix
  return itemId.replace(/^T\d_/, '').replace(/_/g, ' ');
}
